using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;

namespace sv_7ad95e8c02b3483295f0a73992c31e37.Client.Auth;

/// <summary>
/// Client-side AuthenticationStateProvider that reads the auth state
/// persisted by the server during prerendering via PersistentComponentState.
/// This ensures the user's identity survives the transition from server to WebAssembly.
/// </summary>
public sealed class PersistentAuthenticationStateProvider : AuthenticationStateProvider
{
    private static readonly Task<AuthenticationState> _unauthenticated =
        Task.FromResult(new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity())));

    private readonly Task<AuthenticationState> _authenticationStateTask;

    public PersistentAuthenticationStateProvider(PersistentComponentState state)
    {
        if (!state.TryTakeFromJson<UserInfo>(nameof(UserInfo), out var userInfo) || userInfo is null)
        {
            _authenticationStateTask = _unauthenticated;
            return;
        }

        var claims = new List<Claim>
        {
            new(ClaimTypes.Name, userInfo.Name),
            new(ClaimTypes.Email, userInfo.Name),
        };

        foreach (var role in userInfo.Roles)
        {
            claims.Add(new Claim(ClaimTypes.Role, role));
        }

        _authenticationStateTask = Task.FromResult(
            new AuthenticationState(new ClaimsPrincipal(new ClaimsIdentity(claims, nameof(PersistentAuthenticationStateProvider)))));
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
        => _authenticationStateTask;
}

using System.Security.Claims;
using Microsoft.AspNetCore.Components;
using Microsoft.AspNetCore.Components.Authorization;
using Microsoft.AspNetCore.Components.Web;
using sv_7ad95e8c02b3483295f0a73992c31e37.Client.Auth;

namespace sv_7ad95e8c02b3483295f0a73992c31e37.Auth;

/// <summary>
/// Server-side AuthenticationStateProvider that returns a hardcoded user and
/// persists the auth state via PersistentComponentState so the WASM runtime
/// can reconstruct it after the interactive handoff.
/// </summary>
public sealed class HardcodedAuthenticationStateProvider : AuthenticationStateProvider, IDisposable
{
    private readonly PersistentComponentState _persistentState;
    private readonly PersistingComponentStateSubscription _subscription;

    private static readonly AuthenticationState _authState = new(
        new ClaimsPrincipal(new ClaimsIdentity(
        [
            new Claim(ClaimTypes.Name, "bob@example.com"),
            new Claim(ClaimTypes.Email, "bob@example.com"),
            new Claim(ClaimTypes.Role, "User"),
            new Claim(ClaimTypes.Role, "Editor"),
        ], "Hardcoded")));

    public HardcodedAuthenticationStateProvider(PersistentComponentState persistentState)
    {
        _persistentState = persistentState;
        _subscription = _persistentState.RegisterOnPersisting(OnPersistingAsync, RenderMode.InteractiveWebAssembly);
    }

    public override Task<AuthenticationState> GetAuthenticationStateAsync()
        => Task.FromResult(_authState);

    private Task OnPersistingAsync()
    {
        var principal = _authState.User;

        _persistentState.PersistAsJson(nameof(UserInfo), new UserInfo
        {
            Name = principal.FindFirst(ClaimTypes.Name)!.Value,
            Roles = principal.FindAll(ClaimTypes.Role).Select(c => c.Value).ToArray(),
        });

        return Task.CompletedTask;
    }

    public void Dispose() => _subscription.Dispose();
}

